// =============================================
// DARK MODE — Sistema + Toggle con localStorage
// =============================================
(function () {
  var html = document.documentElement;
  var STORAGE_KEY = 'barberaTheme';
  var mq = window.matchMedia('(prefers-color-scheme: dark)');

  function applyTheme(isDark) {
    html.setAttribute('data-theme', isDark ? 'dark' : 'light');
    var btn = document.getElementById('theme-toggle');
    if (btn) {
      btn.setAttribute('aria-label', isDark ? 'Cambiar a modo claro' : 'Cambiar a modo oscuro');
      btn.innerHTML = isDark
        ? '<i class="ti ti-sun"></i>'
        : '<i class="ti ti-moon"></i>';
    }
  }

  // Aplicar tema inicial sin parpadeo (antes del render)
  var saved = localStorage.getItem(STORAGE_KEY);
  if (saved === 'dark') {
    applyTheme(true);
  } else if (saved === 'light') {
    applyTheme(false);
  } else {
    applyTheme(mq.matches);
  }

  // Escuchar cambios del sistema solo si el usuario no eligió manualmente
  mq.addEventListener('change', function (e) {
    if (!localStorage.getItem(STORAGE_KEY)) {
      applyTheme(e.matches);
    }
  });

  // Toggle al hacer clic en el botón
  document.addEventListener('click', function (e) {
    var btn = e.target.closest('#theme-toggle');
    if (!btn) return;
    var isDark = html.getAttribute('data-theme') === 'dark';
    var next = !isDark;
    localStorage.setItem(STORAGE_KEY, next ? 'dark' : 'light');
    applyTheme(next);
  });
})();

$(function () {
  // Admin Panel settings

  //****************************
  /* This is for the mini-sidebar if width is less then 1170*/
  //****************************
  var setsidebartype = function () {
    var width =
      window.innerWidth > 0 ? window.innerWidth : this.screen.width;
    if (width < 1199) {
      $("#main-wrapper").attr("data-sidebartype", "mini-sidebar");
      $("#main-wrapper").addClass("mini-sidebar");
    } else {
      $("#main-wrapper").attr("data-sidebartype", "full");
      $("#main-wrapper").removeClass("mini-sidebar");
    }
  };
  $(window).ready(setsidebartype);
  $(window).on("resize", setsidebartype);
  //****************************
  /* This is for sidebartoggler*/
  //****************************
  $(".sidebartoggler").on("click", function () {
    $("#main-wrapper").toggleClass("mini-sidebar");
    if ($("#main-wrapper").hasClass("mini-sidebar")) {
      $(".sidebartoggler").prop("checked", !0);
      $("#main-wrapper").attr("data-sidebartype", "mini-sidebar");
    } else {
      $(".sidebartoggler").prop("checked", !1);
      $("#main-wrapper").attr("data-sidebartype", "full");
    }
  });
  $(".sidebartoggler").on("click", function () {
    $("#main-wrapper").toggleClass("show-sidebar");
  });

  // Sincronizar ícono del toggle tras DOM ready (por si se aplicó antes del render)
  var isDark = document.documentElement.getAttribute('data-theme') === 'dark';
  var btn = document.getElementById('theme-toggle');
  if (btn) {
    btn.innerHTML = isDark
      ? '<i class="ti ti-sun"></i>'
      : '<i class="ti ti-moon"></i>';
  }
})
